import{_ as e,o as t,c as n,Q as i}from"./chunks/framework.b67c47e6.js";const o="/assets/pl_form.bf7c8f36.png",g=JSON.parse('{"title":"Production Lines","description":"","frontmatter":{},"headers":[],"relativePath":"guide/management/production_lines/index.md","filePath":"guide/management/production_lines/index.md","lastUpdated":1777446226000}'),s={name:"guide/management/production_lines/index.md"},a=i('<h1 id="production-lines" tabindex="-1">Production Lines <a class="header-anchor" href="#production-lines" aria-label="Permalink to &quot;Production Lines&quot;">​</a></h1><p>A company must have at least one production line defined in the system.</p><p>The production line (PL) itself has the following fields:</p><ul><li><strong>Name</strong>: A name to identify the PL.</li><li><strong>Tipo</strong>: Assembly or module categories that the PL can produce.</li><li><strong>Client IDs</strong>: An optional list of external identifiers used to link the production line to external systems (e.g. ERP or planning software). Multiple IDs can be added when the line needs to be matched from more than one external source.</li></ul><p><img src="'+o+'" alt="Production Line Form"></p><p>Production lines (PLs) are expected to have at least 1 station. Stations represent steps in the production process.</p><p>Stations fields:</p><ul><li><strong>Name</strong>: Simply a name.</li><li><strong>Clien ID</strong>: Client ID of the station, usually comes from an external application that the client want to link.</li><li><strong>Zones</strong>: What zones are expected to be produced in this stations. For example add 0 for a typical framing station. If two stations in the same production line share a zone, a warning is shown below the station list indicating which zone is duplicated and in which stations.</li><li><strong>Machine</strong>: If the station is marked as a &quot;machine station&quot;, then you have to define a machine setup that will be linked to this station. For example: A MOBI-ONE station defined in &quot;Machines&quot;.</li></ul><p>As a last nested item, we have checklist items for each station. This will be entries for the production users to be checked in the production interface (&quot;the viewer&quot;).</p><p>Checklist fields:</p><ul><li><strong>Task text</strong>: The text that will be shown to the production user.</li><li><strong>DOCS</strong>: A feature that allows the company to add documentation specific to the task, such as guidelines, specifications, ...</li><li><strong>Branches</strong>: If empty, this is ignored. If filled, selected branches will be searched in the constructible, to see if it&#39;s needed to be added. The station zones are also considered. If station zones exist, then the branch needs to be present in the station zones. Only then the checklist task is included.</li><li><strong>Inclusion criteria</strong>: All means all checklist will get this task. 1/n will be added in 1 checklist each n checklists started. 1/n randomized will do the same but at a random pace.</li></ul>',11),l=[a];function r(d,c,h,p,u,m){return t(),n("div",null,l)}const _=e(s,[["render",r]]);export{g as __pageData,_ as default};
